import { Component, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router } from '@angular/router';
import { AuthService } from '../../core/services/auth.service';
import { Candidate } from '../../core/models';
import { AvatarComponent } from '../../shared/avatar/avatar.component';
import { MatchModalComponent } from '../../shared/match-modal/match-modal.component';

@Component({
  selector: 'app-feed',
  standalone: true,
  imports: [CommonModule, AvatarComponent, MatchModalComponent],
  templateUrl: './feed.component.html',
  styleUrl: './feed.component.css',
})
export class FeedComponent {
  private router = inject(Router);
  private route = inject(ActivatedRoute);
  private auth = inject(AuthService);

  readonly myName = computed(() => this.auth.user()?.name ?? 'You');

  // Data the backend will provide — declared as a typed signal per the data contract.
  readonly candidates = signal<Candidate[]>([
    {
      id: 'u201', name: 'Priya Nair', age: 29, jobTitle: 'Senior Data Scientist', employer: 'Helix Bio',
      location: 'Boston, MA', headline: 'Turning messy data into calm decisions',
      bio: 'ML researcher by day, trail runner by weekend. Looking for someone who is curious, kind, and can debate the best ramen spot in town.',
      mutuals: 4, interests: ['Running', 'Jazz', 'Startups', 'Ramen'], verified: true, likesYou: true,
    },
    {
      id: 'u202', name: 'Daniel Osei', age: 33, jobTitle: 'Engineering Manager', employer: 'Stripe',
      location: 'Brooklyn, NY', headline: 'Building teams and weekend furniture',
      bio: 'I lead a payments team and moonlight as an amateur woodworker. Big on live music, small on doom-scrolling.',
      mutuals: 2, interests: ['Woodworking', 'Live music', 'Cycling'], verified: true, likesYou: false,
    },
    {
      id: 'u203', name: 'Sofia Ramos', age: 27, jobTitle: 'Brand Strategist', employer: 'Wieden+Kennedy',
      location: 'Portland, OR', headline: 'Storyteller who over-orders at brunch',
      bio: 'I make brands sound human. Seeking a partner in crime for gallery openings, farmers markets, and terrible karaoke.',
      mutuals: 6, interests: ['Design', 'Film', 'Coffee', 'Travel'], verified: false, likesYou: true,
    },
    {
      id: 'u204', name: 'Marcus Feld', age: 35, jobTitle: 'Corporate Lawyer', employer: 'Latham & Watkins',
      location: 'Chicago, IL', headline: 'Reads contracts and cook books equally closely',
      bio: 'Recovering workaholic learning to actually take weekends off. Would love someone to explore the city and its restaurants with.',
      mutuals: 1, interests: ['Cooking', 'Tennis', 'Wine'], verified: true, likesYou: false,
    },
    {
      id: 'u205', name: 'Aisha Khan', age: 31, jobTitle: 'Product Manager', employer: 'Notion',
      location: 'San Francisco, CA', headline: 'PM energy, poet heart',
      bio: 'I ship software and write bad haiku. Looking for depth, humour, and a fellow enthusiast of long walks with no destination.',
      mutuals: 3, interests: ['Poetry', 'Hiking', 'Board games'], verified: true, likesYou: true,
    },
    {
      id: 'u206', name: 'Tom Bergström', age: 30, jobTitle: 'Architect', employer: 'Snøhetta',
      location: 'Oslo, NO', headline: 'Designs buildings, collects vinyl',
      bio: 'Scandinavian minimalist looking for maximal conversation. Fan of sauna culture, sailing, and strong filter coffee.',
      mutuals: 0, interests: ['Sailing', 'Vinyl', 'Architecture'], verified: false, likesYou: false,
    },
  ]);

  readonly index = signal(0);
  readonly lastAction = signal<'like' | 'pass' | null>(null);

  readonly current = computed(() => this.candidates()[this.index()] ?? null);
  readonly next = computed(() => this.candidates()[this.index() + 1] ?? null);
  readonly remaining = computed(() => Math.max(0, this.candidates().length - this.index()));
  readonly exhausted = computed(() => this.index() >= this.candidates().length);

  // Match celebration — deep-linkable via ?modal=match
  readonly showMatch = signal(false);
  readonly matchedName = signal('');

  constructor() {
    this.route.queryParamMap.subscribe((params) => {
      const isMatch = params.get('modal') === 'match';
      this.showMatch.set(isMatch);
      if (isMatch) this.matchedName.set(params.get('name') ?? 'Your match');
    });
  }

  pass(): void {
    if (this.exhausted()) return;
    this.lastAction.set('pass');
    this.advance();
  }

  like(): void {
    const c = this.current();
    if (!c) return;
    this.lastAction.set('like');
    this.advance();
    if (c.likesYou) {
      this.router.navigate([], {
        relativeTo: this.route,
        queryParams: { modal: 'match', name: c.name, id: c.id },
      });
    }
  }

  private advance(): void {
    this.index.update((i) => i + 1);
    setTimeout(() => this.lastAction.set(null), 320);
  }

  viewProfile(id: string): void {
    this.router.navigate(['/profile', id]);
  }

  reset(): void {
    this.index.set(0);
  }

  goToMessages(): void {
    this.router.navigate(['/matches']);
  }

  closeMatch(): void {
    this.router.navigate([], { relativeTo: this.route, queryParams: {} });
  }
}
