import { Component, EventEmitter, Input, Output } from '@angular/core';
import { CommonModule } from '@angular/common';
import { AvatarComponent } from '../avatar/avatar.component';

/** Celebration overlay shown when a right-swipe results in a mutual match.
 *  Deep-linkable via `?modal=match` on the feed route. */
@Component({
  selector: 'app-match-modal',
  standalone: true,
  imports: [CommonModule, AvatarComponent],
  templateUrl: './match-modal.component.html',
  styleUrl: './match-modal.component.css',
})
export class MatchModalComponent {
  @Input() matchedName = 'Your match';
  @Input() myName = 'You';
  @Output() message = new EventEmitter<void>();
  @Output() dismiss = new EventEmitter<void>();
}
